5	//! Get spec command - Extract spec text for a pace
6	//!
7	//! Implements the `jjx_get_spec` command which retrieves and outputs the raw
8	//! specification text for a single pace.
9	
10	use std::path::PathBuf;
11	use clap::Args;
12	
13	use vvc::{vvco_out, vvco_err, vvco_Output};
14	
15	use crate::jjrf_favor::jjrf_Coronet as Coronet;
16	use crate::jjrg_gallops::jjrg_Gallops as Gallops;
17	
18	const JJRGS_CMD_NAME_GET_SPEC: &str = "jjx_get_spec";
19	
20	/// Arguments for jjx_get_spec command
21	#[derive(Args, Debug)]
22	pub struct jjrgs_GetSpecArgs {
23	    /// Path to the Gallops JSON file
24	    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
25	    pub file: PathBuf,
26	
27	    /// Target Pace identity (Coronet)
28	    pub coronet: String,
29	}
30	
31	/// Run the get_spec command - output raw spec text
32	pub fn jjrgs_run_get_spec(args: jjrgs_GetSpecArgs) -> (i32, String) {
33	    let cn = JJRGS_CMD_NAME_GET_SPEC;
34	    let mut output = vvco_Output::buffer();
35	
36	    let coronet = match Coronet::jjrf_parse(&args.coronet) {
37	        Ok(c) => c,
38	        Err(e) => {
39	            vvco_err!(output, "{}: error: {}", cn, e);
40	            return (1, output.vvco_finish());
41	        }
42	    };
43	
44	    let gallops = match Gallops::jjrg_load(&args.file) {
45	        Ok(g) => g,
46	        Err(e) => {
47	            vvco_err!(output, "{}: error: {}", cn, e);
48	            return (1, output.vvco_finish());
49	        }
50	    };
51	
52	    // Extract parent firemark and locate heat
53	    let firemark = coronet.jjrf_parent_firemark();
54	    let heat_key = firemark.jjrf_display();
55	    let heat = match gallops.heats.get(&heat_key) {
56	        Some(h) => h,
57	        None => {
58	            vvco_err!(output, "{}: error: Heat '{}' not found", cn, heat_key);
59	            return (1, output.vvco_finish());
60	        }
61	    };
62	
63	    // Locate pace
64	    let coronet_key = coronet.jjrf_display();
65	    let pace = match heat.paces.get(&coronet_key) {
66	        Some(p) => p,
67	        None => {
68	            vvco_err!(output, "{}: error: Pace '{}' not found in Heat '{}'", cn, coronet_key, heat_key);
69	            return (1, output.vvco_finish());
70	        }
71	    };
